fixed_code:
use std::mem;

#[repr(C)]
union MyUnion {
    i: i32,
    f: f64,
}

fn main() {
    let mut u = unsafe { mem::zeroed::<MyUnion>() };
    unsafe { u.i = 42; }
    println!("i: {}
", unsafe { u.i });
}
